using Microsoft.EntityFrameworkCore;
class BlogContext : DbContext
{
    public DbSet<Blog> Blogs => Set<Blog>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Blog>(entity =>
        {
            // Breaking change #1: Default discriminator property renamed "$type".
            // Preserve "Discriminator" so existing documents and raw SQL
            // (e.g. WHERE c.Discriminator = 'Blog') keep working.
            entity.HasDiscriminator<string>("Discriminator");

            // Breaking change #2: id property no longer uses "EntityType|Key"
            // format.  Preserve the old composite format for existing documents.
            entity.Property(b => b.Id).HasConversion(
                v => "Blog|" + v,
                v => v.StartsWith("Blog|") ? v.Substring("Blog|".Length) : v
            );

            // Breaking change #3: HasIndex() now throws for the Cosmos
            // provider (it was silently ignored in EF Core 8).  Removed.
        });
    }
}
class Blog { public string Id { get; set; } public string Name { get; set; } }

